  {
    "phase": 1,
    "build": "pass|fail",
    "vet": "pass|fail",
    "test_count": N,
    "test_baseline": N,
    "test_regression": false,
    "vhs_profiles_pass": 5,
    "vhs_profiles_total": 5,
    "visual_regressions": []
